import React, { useState } from "react";
import axios from "axios";
import { useNavigate, Link } from "react-router-dom";

const ForgotPassword = () => {
  const navigate = useNavigate();
  const [email, setEmail] = useState("");
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage("");
    setError("");

    if (!email) {
      setError("Please enter your email");
      setLoading(false);
      return;
    }

    try {
      console.log("Sending OTP request for:", email);
      
      const res = await axios.post(
        "http://localhost:5000/api/auth/forgot-password",
        { email }
      );

      console.log("Response:", res.data);

      if (res.data.success) {
        setMessage(res.data.message || "OTP sent successfully!");
        localStorage.setItem("resetEmail", email);
        
        setTimeout(() => {
          navigate("/verify-otp");
        }, 2000);
      } else {
        setError(res.data.message || "Failed to send OTP");
      }

    } catch (error) {
      console.error("Error details:", error);
      
      if (error.code === "ERR_NETWORK") {
        setError("Cannot connect to server. Make sure backend is running on port 5000");
      } else if (error.response) {
        setError(error.response.data.message || "Error sending reset email");
      } else {
        setError("An error occurred. Please try again.");
      }
    } finally {
      setLoading(false);
    }
  };

  // Styles object - FIXED the syntax error (line 189)
  const styles = {
    container: {
      minHeight: "100vh",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      background: "#000000",
      padding: "20px"
    },
    card: {
      background: "#111111",
      borderRadius: "10px",
      padding: "40px",
      width: "100%",
      maxWidth: "400px",
      boxShadow: "0 10px 40px rgba(0,0,0,0.5)",
      border: "1px solid #333333"
    },
    title: {
      margin: "0 0 10px 0",
      color: "#ffffff",
      fontSize: "28px",
      fontWeight: "600",
      textAlign: "center"
    },
    subtitle: {
      color: "#cccccc",
      textAlign: "center",
      marginBottom: "30px",
      fontSize: "14px"
    },
    form: {
      display: "flex",
      flexDirection: "column",
      gap: "20px"
    },
    input: {
      padding: "12px 16px",
      background: "#222222",
      border: "1px solid #333333",
      borderRadius: "6px",
      fontSize: "16px",
      color: "#ffffff",
      outline: "none"
    },
    button: {
      padding: "12px",
      background: "#667eea",
      color: "white",
      border: "none",
      borderRadius: "6px",
      fontSize: "16px",
      fontWeight: "600",
      cursor: "pointer"
    },
    buttonDisabled: {
      opacity: 0.6,
      cursor: "not-allowed"
    },
    successMessage: {
      padding: "12px",
      background: "#1a2e1a",
      color: "#8bc34a",
      border: "1px solid #2e4a2e",
      borderRadius: "6px",
      marginBottom: "20px",
      fontSize: "14px"
    },
    errorMessage: {
      padding: "12px",
      background: "#2e1a1a",
      color: "#ff6b6b",
      border: "1px solid #4a2e2e",  // FIXED: Removed extra quotes
      borderRadius: "6px",
      marginBottom: "20px",
      fontSize: "14px"
    },
    links: {
      marginTop: "20px",
      textAlign: "center"
    },
    link: {
      color: "#667eea",
      textDecoration: "none",
      fontSize: "14px"
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <h2 style={styles.title}>Reset Password</h2>
        <p style={styles.subtitle}>Enter your email to receive OTP</p>

        {message && (
          <div style={styles.successMessage}>
            {message}
          </div>
        )}

        {error && (
          <div style={styles.errorMessage}>
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} style={styles.form}>
          <input
            type="email"
            placeholder="Enter your Email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            style={styles.input}
            required
            disabled={loading}
          />

          <button 
            type="submit" 
            style={loading ? {...styles.button, ...styles.buttonDisabled} : styles.button}
            disabled={loading}
          >
            {loading ? "Sending..." : "Send OTP"}
          </button>
        </form>

        <div style={styles.links}>
          <Link to="/login" style={styles.link}>
            Back to Login
          </Link>
        </div>
      </div>
    </div>
  );
};

export default ForgotPassword;
